// Sanitized Wf47 inbound receipt fixture (simulates wf47 Inspect output). No Telegram HTTP.
const scenario = String($('Set Wh test config').first().json.scenario || 'valid_close').trim();
const ui = $('Set Wh test config').first().json;
const ALLOWED = String(ui.allowed_chat_id || '').trim();
const chat_ok = ALLOWED.length > 0 && ALLOWED.indexOf('CONFIGURE') === -1 && ALLOWED.indexOf('**') === -1;
const fixtures = {
  valid_close: { inspect_status: 'accepted', decision_id: 'D-9998-T', selected_option: '1', update_id: 986228910, duplicate_or_stale: false, note_present: false, block_reason: null },
  duplicate: { inspect_status: 'accepted', decision_id: 'D-9998-T', selected_option: '1', update_id: 986228910, duplicate_or_stale: false, note_present: false, block_reason: null },
  unknown: { inspect_status: 'accepted', decision_id: 'D-9999-X', selected_option: '2', update_id: 986228911, duplicate_or_stale: false, note_present: false, block_reason: null },
  stale_closed: { inspect_status: 'accepted', decision_id: 'D-9998-T', selected_option: '2', update_id: 986228912, duplicate_or_stale: false, note_present: false, block_reason: null },
  note_only: { inspect_status: 'note_placeholder', decision_id: 'D-9998-T', selected_option: null, update_id: 986228913, duplicate_or_stale: false, note_present: true, block_reason: null, inbound_text: 'note:D-9998-T:TEST_ONLY_follow_up', response_kind: 'note' },
  malformed: { inspect_status: 'blocked', decision_id: null, selected_option: null, update_id: null, duplicate_or_stale: false, note_present: false, block_reason: 'malformed_response', response_kind: 'malformed' }
};
const f = fixtures[scenario] || fixtures.malformed;
return [{ json: { ...f, allowed_chat_configured: chat_ok, chat_filter_ok: chat_ok, test_only: true, scenario, response_kind: f.response_kind || 'option' } }];

// Wf47 offset/idempotency on wf47_polling_state_test (fixture path).
const inb = $('Build sanitized Wf47 inbound receipt').first().json;
const rows = $('Data Table - Load wf47 polling state').all().map((i) => i.json);
const byKey = (k) => { const r = rows.find((x) => x && x.key === k); return r ? r.value : null; };
const lastHandled = Number(byKey('last_handled_update_id') || 0);
let handled = {};
try { handled = JSON.parse(byKey('handled_keys_json') || '{}'); } catch { handled = {}; }
let wf47_status = 'blocked';
let wf47_block_reason = inb.block_reason || 'no_matching_update';
let wf47_persist = null;
if (!inb.chat_filter_ok) {
  wf47_block_reason = 'allowed_chat_not_configured';
} else if (inb.inspect_status !== 'accepted' || !inb.decision_id) {
  wf47_block_reason = inb.block_reason || 'no_parseable_decision_response';
} else {
  const uid = inb.update_id;
  const key = inb.decision_id + ':' + (inb.selected_option || 'note') + ':' + uid;
  if (uid != null && uid <= lastHandled) {
    wf47_block_reason = 'stale_old_update_id';
  } else if (handled[key]) {
    wf47_block_reason = 'duplicate_or_double_click';
  } else {
    handled[key] = new Date().toISOString();
    wf47_status = 'accepted';
    wf47_block_reason = null;
    wf47_persist = {
      last_update_id: String(uid + 1),
      last_handled_update_id: String(uid),
      handled_keys_json: JSON.stringify(handled)
    };
  }
}
return {
  json: {
    wf47_polling_status: wf47_status,
    wf47_block_reason,
    wf47_persist,
    decision_id: inb.decision_id,
    selected_option: inb.selected_option,
    update_id: inb.update_id,
    note_present: !!inb.note_present,
    response_kind: inb.response_kind || 'option',
    inbound_text: inb.inbound_text || (inb.decision_id ? 'dp:' + inb.decision_id + ':' + inb.selected_option : ''),
    allowed_chat_configured: !!inb.allowed_chat_configured,
    test_only: true
  }
};

const w = $('Wf47 polling offset guard').first().json;
const p = w.wf47_persist;
const note = 'wf47 polling state TEST ONLY';
return [
  { json: { state_key: 'last_update_id', state_value: p.last_update_id, note } },
  { json: { state_key: 'last_handled_update_id', state_value: p.last_handled_update_id, note } },
  { json: { state_key: 'handled_keys_json', state_value: p.handled_keys_json, note } }
];

// Wg correlation from Wf47 sanitized receipt.
const wf = $('Wf47 polling offset guard').item.json;
const rows = $('Data Table - Load wg decision state').all().map((i) => i.json);
const findRow = (id) => rows.find((r) => r && String(r.decision_id) === String(id));
const decision_id = wf.decision_id;
const selected_option = wf.selected_option;
const update_id = wf.update_id;
const note_present = !!wf.note_present;
const response_kind = wf.response_kind || 'option';
let wg_status = 'blocked';
let wg_block_reason = 'malformed_response';
let persist_row = null;
const now = new Date().toISOString();
if (wf.wf47_polling_status !== 'accepted') {
  wg_block_reason = wf.wf47_block_reason || 'wf47_polling_blocked';
} else if (response_kind === 'malformed' || !decision_id) {
  wg_block_reason = 'malformed_response';
} else if (response_kind === 'note') {
  const row = findRow(decision_id);
  if (!row) wg_block_reason = 'unknown_decision_id';
  else {
    wg_status = 'note_recorded';
    wg_block_reason = null;
    persist_row = { decision_id, status: String(row.status || 'open'), selected_option: row.selected_option || '', created_at: row.created_at || now, closed_at: row.closed_at || '', update_id: String(update_id || ''), note_preview: String(wf.inbound_text || '').slice(0, 80), source: 'TEST ONLY' };
  }
} else {
  const row = findRow(decision_id);
  if (!row) wg_block_reason = 'unknown_decision_id';
  else if (String(row.status) === 'closed') {
    wg_block_reason = (update_id != null && String(row.update_id) === String(update_id)) ? 'duplicate_or_already_closed' : 'already_closed_or_stale';
  } else if (String(row.status) === 'open' && ['1','2','3'].includes(String(selected_option))) {
    wg_status = 'closed';
    wg_block_reason = null;
    persist_row = { decision_id, status: 'closed', selected_option: String(selected_option), created_at: row.created_at || now, closed_at: now, update_id: String(update_id), note_preview: row.note_preview || '', source: 'TEST ONLY' };
  } else wg_block_reason = 'malformed_response';
}
return {
  json: {
    wf47_polling_status: wf.wf47_polling_status,
    wf47_block_reason: wf.wf47_block_reason,
    wg_correlation_status: wg_status,
    wg_block_reason,
    decision_id,
    selected_option,
    update_id,
    note_present,
    prior_status: decision_id ? (findRow(decision_id)?.status || 'missing') : 'missing',
    wg_persist_row: persist_row,
    test_only: true
  }
};

const c = $('Correlate Wg decision state').item.json;
return {
  json: {
    inspect_status: c.wg_correlation_status === 'closed' ? 'closed' : (c.wg_correlation_status === 'note_recorded' ? 'note_recorded' : 'blocked'),
    wf47_polling_status: c.wf47_polling_status,
    wg_correlation_status: c.wg_correlation_status,
    decision_id: c.decision_id,
    selected_option: c.selected_option,
    update_id: c.update_id,
    note_present: c.note_present,
    wf47_block_reason: c.wf47_block_reason,
    wg_block_reason: c.wg_block_reason,
    prior_status: c.prior_status,
    state_persisted_wf47: c.wf47_polling_status === 'accepted',
    state_persisted_wg: c.wg_persist_row !== null && c.wg_persist_row !== undefined,
    test_only: true
  }
};

const d = $input.item.json;
return {
  json: {
    inspect_status: d.inspect_status,
    wf47_polling_status: d.wf47_polling_status,
    wg_correlation_status: d.wg_correlation_status,
    decision_id: d.decision_id || null,
    selected_option: d.selected_option || null,
    update_id: d.update_id ?? null,
    note_present: d.note_present || false,
    wf47_block_reason: d.wf47_block_reason || null,
    wg_block_reason: d.wg_block_reason || null,
    prior_status: d.prior_status || null,
    state_persisted_wf47: d.state_persisted_wf47 === true,
    state_persisted_wg: d.state_persisted_wg === true,
    test_only: true
  }
};
